mapper.select:
SELECT log_id AS logId, operation_type AS operationType, operation_name AS operationName, request_method AS requestMethod, request_url AS requestUrl, request_params AS requestParams, response_result AS responseResult, user_id AS userId, user_name AS userName, user_type AS userType, campus_name AS campusName, ip_address AS ipAddress, ip_location AS ipLocation, os AS os, browser AS browser, duration AS duration, module AS module, status AS status, error_msg AS errorMsg, DATE_FORMAT(operate_time, '%Y-%m-%d %H:%i:%s') AS operateTime FROM sys_operation_log
is_deleted = 0
AND operation_type = #{req.operationType}
AND operation_name LIKE CONCAT('%', #{req.operationName}, '%')
AND (user_name LIKE CONCAT('%', #{req.keyword}, '%') OR request_url LIKE CONCAT('%', #{req.keyword}, '%') OR ip_address LIKE CONCAT('%', #{req.keyword}, '%'))
AND DATE(operate_time) >= #{req.startDate}
AND DATE(operate_time) <= #{req.endDate}
ORDER BY operate_time DESC
